themes.css:
* { box-sizing: border-box; margin: 0; padding: 0; }
html, body { width: 100%; height: 100%; overflow: hidden; background: transparent; }
body { font-family: "Montserrat", sans-serif; }

@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes tickerMove {
  0% { transform: translateX(0%); }
  100% { transform: translateX(-50%); }
}
@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: .45; }
}

.lt { position: fixed; z-index: 40; pointer-events: none; }
.lt[data-state="in"] { animation: fadeInUp .6s cubic-bezier(0.16,1,0.3,1) both; }
.lt[data-state="out"] { animation: fadeOutDown .4s cubic-bezier(.4,0,1,1) both; }

.pos-bl { left: 40px; bottom: 32px; }
.pos-br { right: 40px; bottom: 32px; }
.pos-bc { left: 50%; bottom: 32px; transform: translateX(-50%); }
.pos-tl { left: 40px; top: 32px; }
.pos-tr { right: 40px; top: 32px; }
.pos-tc { left: 50%; top: 32px; transform: translateX(-50%); }
.pos-full-bottom { left: 0; right: 0; bottom: 0; }

.panel {
  background: var(--bg, rgba(20,20,20,.85));
  color: var(--fg, #fff);
  border: 1px solid var(--bd, rgba(255,255,255,.14));
  border-radius: 14px;
  box-shadow: 0 12px 40px rgba(0,0,0,.28);
  backdrop-filter: blur(2px);
}

.row { display: flex; align-items: center; }
.col { display: flex; flex-direction: column; min-width: 0; }

.kicker {
  display: inline-block;
  font-size: 15px;
  font-weight: 700;
  letter-spacing: .08em;
  text-transform: uppercase;
  margin-bottom: 8px;
  color: var(--accent, #4a6bcb);
}

.headline {
  font-size: clamp(28px, 2.1vw, 54px);
  font-weight: 800;
  line-height: 1.08;
  letter-spacing: .005em;
}

.subline {
  margin-top: 6px;
  font-size: clamp(17px, 1.32vw, 34px);
  font-weight: 500;
  line-height: 1.2;
  opacity: .94;
}

.meta {
  margin-top: 8px;
  font-size: clamp(14px, 1vw, 24px);
  font-weight: 600;
  letter-spacing: .05em;
  text-transform: uppercase;
  opacity: .88;
}

.speaker-panel {
  display: flex;
  align-items: center;
  gap: 18px;
  min-width: 760px;
  max-width: min(1500px, calc(100vw - 80px));
  padding: 20px 24px;
}

.logo-box {
  width: 170px;
  min-width: 170px;
  height: 96px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(255,255,255,.02);
}

.logo-box.logo-round {
  width: 88px;
  min-width: 88px;
  height: 88px;
  border-radius: 999px;
  border: 2px solid rgba(255,255,255,.18);
}

.logo-box img { max-width: 100%; max-height: 100%; object-fit: contain; }

.v-divider {
  width: 6px;
  min-width: 6px;
  height: 94px;
  border-radius: 2px;
  background: var(--accent, #4a6bcb);
}

.name-line {
  font-size: clamp(30px, 2.55vw, 62px);
  font-weight: 800;
  line-height: 1;
  text-transform: uppercase;
}

.role-line {
  margin-top: 9px;
  font-size: clamp(20px, 1.82vw, 42px);
  font-weight: 500;
  line-height: 1.15;
}

.quote-panel {
  max-width: min(1450px, calc(100vw - 80px));
  min-width: 680px;
  padding: 18px 24px 20px;
}

.quote-text {
  font-family: "Source Serif 4", serif;
  font-size: clamp(29px, 2.25vw, 55px);
  line-height: 1.22;
  font-weight: 600;
}

.quote-ref {
  margin-top: 10px;
  text-align: right;
  font-size: clamp(16px, 1.1vw, 26px);
  font-weight: 700;
  letter-spacing: .05em;
  text-transform: uppercase;
  opacity: .9;
}

.announce-panel {
  display: flex;
  align-items: center;
  gap: 16px;
  min-width: 640px;
  max-width: min(1280px, calc(100vw - 80px));
  padding: 14px 18px;
}

.tag-box {
  background: var(--accent, #4a6bcb);
  color: var(--tagFg, #fff);
  border-radius: 10px;
  padding: 9px 14px;
  font-size: 14px;
  font-weight: 800;
  letter-spacing: .08em;
  text-transform: uppercase;
  white-space: nowrap;
}

.keyword-panel {
  display: inline-flex;
  align-items: center;
  gap: 14px;
  max-width: min(1250px, calc(100vw - 80px));
  padding: 12px 16px;
}

.keyword-main {
  font-size: clamp(30px, 2.35vw, 56px);
  font-weight: 800;
  line-height: 1;
  letter-spacing: .01em;
  text-transform: uppercase;
}

.keyword-sub {
  font-size: clamp(16px, 1.06vw, 24px);
  font-weight: 600;
  opacity: .92;
}

.date-shell {
  display: flex;
  align-items: stretch;
  gap: 14px;
  min-width: 650px;
  max-width: min(1180px, calc(100vw - 80px));
  padding: 12px 14px;
}

.date-box {
  min-width: 92px;
  border-radius: 10px;
  background: var(--accent, #4a6bcb);
  color: #fff;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 8px 10px;
}

.date-box .mth {
  font-size: 14px;
  font-weight: 700;
  letter-spacing: .08em;
  text-transform: uppercase;
}

.date-box .dy {
  font-size: 36px;
  font-weight: 800;
  line-height: 1;
}

.pill {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  padding: 10px 16px;
  border-radius: 999px;
  background: var(--bg, rgba(16,16,16,.78));
  border: 1px solid var(--bd, rgba(255,255,255,.18));
  box-shadow: 0 10px 24px rgba(0,0,0,.28);
  color: var(--fg, #fff);
}

.dot {
  width: 10px;
  height: 10px;
  border-radius: 999px;
  background: var(--accent, #e53935);
  animation: pulse 1.6s ease-in-out infinite;
}

.pill-label {
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: .11em;
  font-weight: 700;
  color: var(--accent, #e53935);
}

.pill-time {
  font-size: 24px;
  font-weight: 800;
  letter-spacing: .08em;
  font-variant-numeric: tabular-nums;
}

.pill-context {
  font-size: 14px;
  font-weight: 600;
  opacity: .9;
  text-transform: uppercase;
  letter-spacing: .05em;
}

.social-row {
  display: flex;
  align-items: center;
  gap: 12px;
  min-width: 560px;
  max-width: min(980px, calc(100vw - 80px));
  padding: 12px 14px;
}

.platform-pill {
  background: rgba(255,255,255,.14);
  border-radius: 999px;
  padding: 7px 11px;
  font-size: 13px;
  text-transform: uppercase;
  font-weight: 700;
  letter-spacing: .08em;
}

.handle {
  font-size: clamp(21px, 1.56vw, 34px);
  font-weight: 700;
}

.ticker-shell {
  width: min(1880px, calc(100vw - 24px));
  margin: 0 auto 10px;
  height: 56px;
  border-radius: 12px;
  overflow: hidden;
  background: var(--bg, #111);
  border: 1px solid var(--bd, rgba(255,255,255,.14));
  box-shadow: 0 10px 26px rgba(0,0,0,.35);
  display: flex;
  align-items: stretch;
}

.ticker-badge {
  background: var(--accent, #4a6bcb);
  color: var(--tagFg, #fff);
  min-width: 142px;
  padding: 0 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: .09em;
}

.ticker-track {
  flex: 1;
  overflow: hidden;
  display: flex;
  align-items: center;
  white-space: nowrap;
}

.ticker-move {
  display: inline-flex;
  white-space: nowrap;
  gap: 48px;
  padding-left: 28px;
  font-size: 18px;
  font-weight: 600;
  letter-spacing: .01em;
  animation: tickerMove var(--speed, 20s) linear infinite;
}

.info-panel {
  min-width: 560px;
  max-width: min(980px, calc(100vw - 80px));
  padding: 14px 18px;
}

.line-list {
  margin-top: 8px;
  display: flex;
  flex-direction: column;
  gap: 5px;
  font-size: clamp(16px, 1vw, 22px);
  font-weight: 600;
  line-height: 1.25;
}

@media (max-width: 1180px) {
  .pos-bl, .pos-br, .pos-bc, .pos-tl, .pos-tr, .pos-tc { left: 20px; right: 20px; transform: none; }
  .pos-br, .pos-tr { left: auto; }
  .pos-bc, .pos-tc { left: 20px; right: 20px; }
  .speaker-panel, .quote-panel, .announce-panel, .date-shell, .social-row, .info-panel { min-width: 0; max-width: calc(100vw - 40px); }
  .speaker-panel { padding: 14px 16px; gap: 14px; }
  .logo-box { width: 116px; min-width: 116px; height: 70px; }
  .logo-box.logo-round { width: 64px; min-width: 64px; height: 64px; }
  .v-divider { height: 70px; }
}
@keyframes fadeOutDown {
  from { opacity: 1; transform: translateY(0); }
  to { opacity: 0; transform: translateY(20px); }
}

