/* IN: stagger (background -> first text -> second text/meta) */
.ylt[data-state="in"][data-mode="stagger"] .y-shell { animation: yBgIn .46s cubic-bezier(0.16,1,0.3,1) both; }
.ylt[data-state="in"][data-mode="stagger"] .y-enter-1 { animation: yTextInUp .35s cubic-bezier(0.16,1,0.3,1) .16s both; }
.ylt[data-state="in"][data-mode="stagger"] .y-enter-2 { animation: yTextInUp .35s cubic-bezier(0.16,1,0.3,1) .28s both; }
.ylt[data-state="in"][data-mode="stagger"] .y-enter-3 { animation: yTextInFade .32s cubic-bezier(0.16,1,0.3,1) .39s both; }

/* OUT: first text -> second text/meta -> background */
.ylt[data-state="out"][data-mode="stagger"] .y-enter-1 { animation: yTextOutUp .26s cubic-bezier(.4,0,1,1) both; }
.ylt[data-state="out"][data-mode="stagger"] .y-enter-2 { animation: yTextOutDown .24s cubic-bezier(.4,0,1,1) .08s both; }
.ylt[data-state="out"][data-mode="stagger"] .y-enter-3 { animation: yTextOutDown .22s cubic-bezier(.4,0,1,1) .15s both; }
.ylt[data-state="out"][data-mode="stagger"] .y-shell { animation: yBgOut .34s cubic-bezier(.4,0,1,1) .24s both; }

/* IN: together-slow */
.ylt[data-state="in"][data-mode="slow"] .y-shell { animation: yBgIn .8s cubic-bezier(0.16,1,0.3,1) both; }
.ylt[data-state="in"][data-mode="slow"] .y-enter-1 { animation: yTextInUp .64s cubic-bezier(0.16,1,0.3,1) .18s both; }
.ylt[data-state="in"][data-mode="slow"] .y-enter-2 { animation: yTextInUp .66s cubic-bezier(0.16,1,0.3,1) .28s both; }
.ylt[data-state="in"][data-mode="slow"] .y-enter-3 { animation: yTextInFade .64s cubic-bezier(0.16,1,0.3,1) .36s both; }

/* OUT: slow */
.ylt[data-state="out"][data-mode="slow"] .y-enter-1 { animation: yTextOutUp .34s cubic-bezier(.4,0,1,1) both; }
.ylt[data-state="out"][data-mode="slow"] .y-enter-2 { animation: yTextOutDown .34s cubic-bezier(.4,0,1,1) .1s both; }
.ylt[data-state="out"][data-mode="slow"] .y-enter-3 { animation: yTextOutDown .31s cubic-bezier(.4,0,1,1) .2s both; }
.ylt[data-state="out"][data-mode="slow"] .y-shell { animation: yBgOut .45s cubic-bezier(.4,0,1,1) .34s both; }

