html, body { width: 100%; height: 100%; overflow: hidden; background: transparent; }
body { font-family: "Outfit", sans-serif; }

.ylt {
  position: fixed;
  z-index: 50;
  pointer-events: none;
  color: var(--fg, #ffffff);
  --bg1: #0f172a;
  --bg2: #111827;
  --accent: #38bdf8;
  --muted: rgba(255,255,255,.75);
  --border: rgba(255,255,255,.22);
  --glow: rgba(56,189,248,.24);
}

.y-pos-bl { left: 34px; bottom: 30px; }
.y-pos-br { right: 34px; bottom: 30px; }
.y-pos-bc { left: 50%; bottom: 30px; transform: translateX(-50%); }
.y-pos-tl { left: 34px; top: 30px; }
.y-pos-tr { right: 34px; top: 30px; }
.y-pos-tc { left: 50%; top: 30px; transform: translateX(-50%); }

.y-shell {
  position: relative;
  overflow: hidden;
  border: 1px solid var(--border);
  background: linear-gradient(135deg, var(--bg1), var(--bg2));
  box-shadow:
    0 14px 44px rgba(0,0,0,.42),
    0 0 0 1px rgba(255,255,255,.04) inset,
    0 0 24px var(--glow);
}

.y-shell::before {
  content: "";
  position: absolute;
  inset: 0;
  background:
    radial-gradient(420px 180px at 0% 100%, rgba(255,255,255,.1), transparent 70%),
    linear-gradient(95deg, transparent 0 32%, rgba(255,255,255,.08) 48%, transparent 66%);
  mix-blend-mode: screen;
  pointer-events: none;
}

.y-shell::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  top: 0;
  height: 3px;
  background: linear-gradient(90deg, transparent, var(--accent), transparent);
  opacity: .92;
}

.y-shell,
.y-enter-1,
.y-enter-2,
.y-enter-3 {
  opacity: 0;
}

/* Fallback visibility when animation vars are missing/unresolved in host renderer */
.ylt:not([data-state="in"]):not([data-state="out"]) .y-shell,
.ylt:not([data-state="in"]):not([data-state="out"]) .y-enter-1,
.ylt:not([data-state="in"]):not([data-state="out"]) .y-enter-2,
.ylt:not([data-state="in"]):not([data-state="out"]) .y-enter-3,
.ylt:not([data-mode="stagger"]):not([data-mode="slow"]):not([data-mode="together"]) .y-shell,
.ylt:not([data-mode="stagger"]):not([data-mode="slow"]):not([data-mode="together"]) .y-enter-1,
.ylt:not([data-mode="stagger"]):not([data-mode="slow"]):not([data-mode="together"]) .y-enter-2,
.ylt:not([data-mode="stagger"]):not([data-mode="slow"]):not([data-mode="together"]) .y-enter-3 {
  opacity: 1;
}

